import{_ as t,c as n,o as i,ae as r}from"./chunks/framework.CeIuOzFV.js";const c=JSON.parse('{"title":"KI-Konfiguration","description":"","frontmatter":{},"headers":[],"relativePath":"de/user-manual/settings/ai.md","filePath":"de/user-manual/settings/ai.md"}'),a={name:"de/user-manual/settings/ai.md"};function s(o,e,l,u,d,g){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="ki-konfiguration" tabindex="-1">KI-Konfiguration <a class="header-anchor" href="#ki-konfiguration" aria-label="Permalink to &quot;KI-Konfiguration&quot;">​</a></h1><h2 id="konfiguration" tabindex="-1">Konfiguration <a class="header-anchor" href="#konfiguration" aria-label="Permalink to &quot;Konfiguration&quot;">​</a></h2><p>Die KI-Konfigurationsseite ermöglicht die Einrichtung der Integration künstlicher Intelligenz in Artivact für Funktionen wie automatische Übersetzung und Text-to-Speech (TTS) Audiogenerierung.</p><p>Die Seite ist über das Systemeinstellungsmenü erreichbar und kann nur von Administratoren aufgerufen werden.</p><h2 id="einstellungen" tabindex="-1">Einstellungen <a class="header-anchor" href="#einstellungen" aria-label="Permalink to &quot;Einstellungen&quot;">​</a></h2><p>Die folgenden Konfigurationsmöglichkeiten stehen zur Verfügung:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Einstellung</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;">KI aktivieren</td><td style="text-align:left;">Aktiviert oder deaktiviert alle KI-Funktionen in der Anwendung.</td></tr><tr><td style="text-align:left;">API-Schlüssel</td><td style="text-align:left;">Der API-Schlüssel zur Authentifizierung beim KI-Dienst (z.B. OpenAI).</td></tr><tr><td style="text-align:left;">Übersetzungs-Prompt</td><td style="text-align:left;">Ein Prompt-Template für automatische Übersetzungen. Der Platzhalter <code>{locale}</code> wird durch die Zielsprache ersetzt. Siehe <a href="./../content-management/internationalization.html">I18N</a> für weitere Details zu Übersetzungen.</td></tr><tr><td style="text-align:left;">TTS-Stimme</td><td style="text-align:left;">Die Stimmen-ID, die für die Text-to-Speech-Audiogenerierung verwendet wird (z.B. <code>alloy</code>).</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">API-Schlüssel</p><p>Der API-Schlüssel ist für alle KI-Funktionen erforderlich. Ohne einen gültigen API-Schlüssel stehen automatische Übersetzung und Audiogenerierung nicht zur Verfügung.</p></div><h2 id="automatische-ubersetzung" tabindex="-1">Automatische Übersetzung <a class="header-anchor" href="#automatische-ubersetzung" aria-label="Permalink to &quot;Automatische Übersetzung&quot;">​</a></h2><p>Wenn die KI aktiviert und konfiguriert ist, kann Artivact Texte von Sammlungsobjekten und Seiteninhalte automatisch in die konfigurierten Sprachen übersetzen.</p><p>Die Übersetzung basiert auf dem <strong>Übersetzungs-Prompt</strong>. Das Prompt-Template kann angepasst werden, um zu beeinflussen, wie die KI Übersetzungen durchführt.</p><p>Siehe <a href="./../content-management/internationalization.html">I18N</a> für Details zur Verwaltung mehrsprachiger Inhalte.</p><h2 id="audiogenerierung-tts" tabindex="-1">Audiogenerierung (TTS) <a class="header-anchor" href="#audiogenerierung-tts" aria-label="Permalink to &quot;Audiogenerierung (TTS)&quot;">​</a></h2><p>Wenn die KI aktiviert und konfiguriert ist, kann Artivact Audioinhalte aus Text mittels Text-to-Speech generieren.</p><p>Die Audiogenerierung basiert auf der konfigurierten <strong>TTS-Stimme</strong>. Die erzeugten Audiodateien können z.B. in Content-Exporten verwendet werden.</p><p>Die verfügbaren Stimmen hängen vom konfigurierten KI-Anbieter ab.</p>',16)])])}const m=t(a,[["render",s]]);export{c as __pageData,m as default};
